    workspace = kzalloc(sizeof(*workspace), GFP_KERNEL);
    if (!workspace)
        return ERR_PTR(-ENOMEM);

    workspacesize = max(zlib_deflate_workspacesize(MAX_WBITS, MAX_MEM_LEVEL),
